  import sailpoint.object.Identity;
  import sailpoint.tools.Util;

  List userList = new ArrayList();
  userList.add("10614724");
  userList.add("10547026");
  userList.add("10462111");
  userList.add("10463730");

  if(identity != null && !identity.isInactive()){
    String email = identity.getAttribute("primaryEmail");
    if(Util.isNotNullOrEmpty(email)){
      Identity manager = identity.getManager();
      int i=1;

      while (null != manager){
       // if(null!=manager && manager.getName().equalsIgnoreCase("10387647")){ 
        if(null!=manager && Util.nullSafeContains(userList, manager.getName())){ 
          //Eduardo Conrado
          return true;
        }
        i++;
        Identity ident=manager;
        manager = ident.getManager();  

        //failsafe in case of loop in chain
        if(i > 50)
          break;
      }
     // if (identity.getName().equalsIgnoreCase("10387647"))
      if(Util.nullSafeContains(userList, identity.getName()))
      {
        return true;
      }	
    }
  }

  return false;
